<?php require_once __DIR__.'/../includes/business-header.php';$lesson=business_lesson($pdo,(int)($_GET['lesson']??0));if(!$lesson){http_response_code(404);exit('Lesson not found.');}$quiz=business_quiz($pdo,(int)$lesson['id']);if(!$quiz)exit('Quiz coming soon.');$result=null;if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){$correct=0;$feedback=[];foreach($quiz['questions'] as $q){$answer=(string)($_POST['q'.$q['id']]??'');$ok=hash_equals((string)$q['correct_answer'],$answer);if($ok)$correct++;$feedback[$q['id']]=['ok'=>$ok,'explanation'=>$q['explanation']];}$total=count($quiz['questions']);$score=$total?(int)round($correct*100/$total):0;$result=['score'=>$score,'passed'=>$score>=(int)$quiz['pass_mark'],'feedback'=>$feedback];if(learner_logged_in()&&$result['passed']){mark_business_progress($pdo,learner_id(),(int)$lesson['course_id'],(int)$lesson['id'],null,$score);award_business_badge($pdo,learner_id(),$quiz['badge_id']?(int)$quiz['badge_id']:null);}}?>
<section class="business-quiz"><div class="biz-container"><div class="activity-title"><a class="biz-back" href="<?=business_url('lesson.php?id='.(int)$lesson['id'])?>">← Back to lesson</a><span class="biz-eyebrow">Capability check</span><h1><?=e($quiz['title'])?></h1><p>Pass mark: <?=(int)$quiz['pass_mark']?>%. Use the feedback to strengthen your approach.</p></div><?php if($result):?><div class="biz-quiz-result <?=$result['passed']?'passed':'review'?>"><span><?=$result['passed']?'✓':'↻'?></span><div><small><?=$result['passed']?'CAPABILITY VERIFIED':'REVIEW AND RETRY'?></small><h2><?=$result['score']?>%</h2><p><?=$result['passed']?'You demonstrated the core business decisions in this lesson.':'Use the explanations below, then try again.'?></p></div></div><?php endif?><form class="biz-quiz-form" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><?php foreach($quiz['questions'] as $i=>$q):?><fieldset><legend><span><?=str_pad((string)($i+1),2,'0',STR_PAD_LEFT)?></span><?=e($q['question'])?></legend><?php foreach(business_json($q['options_json']) as $option):?><label><input type="radio" name="q<?=(int)$q['id']?>" value="<?=e($option)?>" required><span><?=e($option)?></span></label><?php endforeach?><?php if($result):?><p class="quiz-feedback <?=$result['feedback'][$q['id']]['ok']?'correct':'wrong'?>"><?=$result['feedback'][$q['id']]['ok']?'Correct — strong decision.':'Review: '.e($result['feedback'][$q['id']]['explanation'])?></p><?php endif?></fieldset><?php endforeach?><button class="biz-btn gold"><?=$result?'Try the check again':'Submit decisions ↗'?></button></form></div></section>
